files.css:
body { font-family: system-ui, sans-serif; padding: 1.5rem; }
h2 { font-size: 1rem; color: #2563eb; margin-bottom: 0.35rem; }
.disc-list { list-style-type: disc; line-height: 1.8; }
.num-list { list-style-type: decimal; line-height: 1.8; color: #334155; }

.flex-nav {
  display: flex;
  gap: 1rem;
  padding: 0.75rem 1rem;
  background: #1e293b;
  font-family: sans-serif;
}
.flex-nav a { color: #93c5fd; text-decoration: none; }
.flex-center {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100px;
  background: #f1f5f9;
  margin-top: 0.5rem;
}
.box { background: #2563eb; color: #fff; padding: 1rem 1.5rem; border-radius: 8px; }

.grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
  padding: 1rem;
  font-family: system-ui, sans-serif;
}
.cell {
  background: #dbeafe;
  padding: 1.5rem;
  text-align: center;
  border-radius: 8px;
  font-weight: 600;
  color: #1e40af;
}

body { font-family: system-ui, sans-serif; padding: 1rem; min-height: 200px; }
.stage {
  position: relative;
  height: 140px;
  background: #f1f5f9;
  border: 1px dashed #94a3b8;
  border-radius: 8px;
  padding: 1rem;
}
.box {
  display: inline-block;
  padding: 0.5rem 0.75rem;
  margin: 0.25rem;
  background: #dbeafe;
  border-radius: 4px;
  font-size: 0.85rem;
}
.relative { position: relative; top: 10px; left: 8px; background: #fef08a; }
.absolute { position: absolute; bottom: 12px; right: 12px; background: #bbf7d0; }
.fixed-badge {
  position: fixed;
  bottom: 12px;
  right: 12px;
  background: #2563eb;
  color: #fff;
  padding: 0.4rem 0.75rem;
  border-radius: 6px;
  font-size: 0.8rem;
}

body { font-family: Georgia, serif; padding: 1.5rem; max-width: 36rem; line-height: 1.6; }
.float-box {
  float: left;
  width: 100px;
  height: 80px;
  margin: 0 1rem 0.5rem 0;
  background: #7c3aed;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.85rem;
  border-radius: 6px;
}
.clear { clear: both; color: #64748b; font-size: 0.95rem; }

